/* HealingMart Calculator Detail Shell v1.4.0 */
(function (w, d) {
  "use strict";

  var script = d.currentScript;
  var explicitBase = script && script.dataset ? (script.dataset.base || "") : "";
  var src = script && script.src ? script.src : "";
  var base = (explicitBase || src.replace(/\/dist\/js\/hm-calc-detail[^/]*\.js(?:\?.*)?$/, "")).replace(/\/$/, "");
  var dist = base + "/dist";

  function esc(value) {
    return String(value == null ? "" : value).replace(/[&<>"']/g, function (ch) {
      return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[ch];
    });
  }

  function ensureCss() {
    if (d.getElementById("hm-calc-css-v1")) return;
    var link = d.createElement("link");
    link.id = "hm-calc-css-v1";
    link.rel = "stylesheet";
    link.href = dist + "/css/hm-calc.v1.css?v=1.4.0";
    d.head.appendChild(link);
  }

  function loadScript(url, attrs) {
    return new Promise(function (resolve, reject) {
      var s = d.createElement("script");
      s.src = url;
      if (attrs) Object.keys(attrs).forEach(function (key) { s.setAttribute(key, attrs[key]); });
      s.onload = resolve;
      s.onerror = reject;
      d.head.appendChild(s);
    });
  }

  function icon(id) {
    var paths = {
      life: '<path d="M5 4h14v16H5z"></path><path d="M8 8h8M8 12h3M13 12h3M8 16h3M13 16h3"></path>',
      finance: '<path d="M4 9h16M6 9V6l6-3 6 3v3M6 9v9M10 9v9M14 9v9M18 9v9M4 18h16v3H4z"></path>',
      health: '<path d="M12 21s-7-4.35-7-10a4 4 0 0 1 7-2.65A4 4 0 0 1 19 11c0 5.65-7 10-7 10z"></path><path d="M8.5 13h2l1-3 1.5 5 1-2h2"></path>',
      date: '<rect x="4" y="5" width="16" height="15" rx="2"></rect><path d="M8 3v4M16 3v4M4 9h16M8 13h2M12 13h2M16 13h1"></path>',
      unit: '<path d="M4 7h16v10H4z"></path><path d="M7 7v4M10 7v2M13 7v4M16 7v2"></path>',
      math: '<path d="M5 6h6M8 3v6M14 5l5 5M19 5l-5 5M5 15h6M14 16h5"></path><circle cx="16.5" cy="13.5" r=".6"></circle><circle cx="16.5" cy="18.5" r=".6"></circle>',
      "payroll-tax": '<path d="M6 3h12v18l-3-2-3 2-3-2-3 2V3z"></path><path d="M9 8h6M9 12h6M9 16h3"></path>',
      "real-estate": '<path d="M3 11l9-8 9 8"></path><path d="M5 10v10h14V10M9 20v-6h6v6"></path>',
      auto: '<path d="M5 16h14l-1-6-2-3H8L6 10l-1 6z"></path><path d="M4 16v3h3v-2h10v2h3v-3M7 13h2M15 13h2"></path>',
      education: '<path d="M4 5h7a3 3 0 0 1 3 3v11a3 3 0 0 0-3-3H4V5z"></path><path d="M20 5h-3a3 3 0 0 0-3 3v11a3 3 0 0 1 3-3h3V5z"></path>',
      food: '<path d="M7 3v8M4 3v5a3 3 0 0 0 6 0V3M7 11v10M16 3v18M16 3c3 2 4 5 4 8h-4"></path>',
      science: '<path d="M9 3h6M10 3v6l-5 9a2 2 0 0 0 2 3h10a2 2 0 0 0 2-3l-5-9V3"></path><path d="M8 15h8"></path>'
    };
    return '<svg viewBox="0 0 24 24" aria-hidden="true">' + (paths[id] || paths.life) + '</svg>';
  }

  function normalizeText(text) {
    return String(text == null ? "" : text)
      .replace(/(?:&amp;)?#39;?/g, "'")
      .replace(/(?:&amp;)?#183;?/g, "·")
      .replace(/(?:&amp;)?#215;?/g, "×")
      .replace(/(?:&amp;)?#8230;?/g, "…")
      .replace(/(?:&amp;)?#572;?/g, "");
  }

  function cleanTextNodes(root) {
    if (!root || !d.createTreeWalker) return;
    var walker = d.createTreeWalker(root, NodeFilter.SHOW_TEXT, null);
    var node;
    while ((node = walker.nextNode())) {
      var next = normalizeText(node.nodeValue);
      if (next !== node.nodeValue) node.nodeValue = next;
    }
  }

  function belongs(calc, categoryId) {
    var list = Array.isArray(calc.categories) ? calc.categories : [calc.category || calc.primaryCategory];
    return list.indexOf(categoryId) !== -1;
  }

  function categoryCalcs(calculators, categoryId) {
    return calculators.filter(function (calc) { return belongs(calc, categoryId); });
  }

  function isCategoryAvailable(cat, calculators) {
    return cat && cat.status === "active" && categoryCalcs(calculators, cat.id).length > 0;
  }

  function calculatorHref(calc, categoryId) {
    if (calc.bloggerReady === true && calc.bloggerUrl) return calc.bloggerUrl;
    return base + "/calculator.html?id=" + encodeURIComponent(calc.id) + "&category=" + encodeURIComponent(categoryId || calc.primaryCategory || "life");
  }

  function categoryHref(categoryId) {
    return base + "/category.html?category=" + encodeURIComponent(categoryId);
  }

  function navHtml(categories, calculators, selectedId) {
    return '<nav class="hm-category-pills" aria-label="계산기 카테고리">' +
      '<a class="hm-category-pill is-all" href="' + esc(base + '/') + '">전체</a>' +
      categories.map(function (cat) {
        if (!isCategoryAvailable(cat, calculators)) {
          return '<span class="hm-category-pill is-' + esc(cat.id) + ' is-coming" aria-disabled="true" title="준비 중">' + icon(cat.id) + '<span>' + esc(cat.name) + '</span></span>';
        }
        return '<a class="hm-category-pill is-' + esc(cat.id) + (cat.id === selectedId ? ' is-active' : '') + '" href="' + esc(categoryHref(cat.id)) + '">' + icon(cat.id) + '<span>' + esc(cat.name) + '</span></a>';
      }).join('') + '</nav>';
  }

  function contentHtml(calc) {
    var content = calc.content || {};
    var useCases = (content.useCases || []).map(function (v) { return '<li>' + esc(v) + '</li>'; }).join('');
    var notes = (content.notes || []).map(function (v) { return '<li>' + esc(v) + '</li>'; }).join('');
    var faq = (content.faq || []).map(function (v) { return '<details class="hm-seo-faq"><summary>' + esc(v.q) + '</summary><p>' + esc(v.a) + '</p></details>'; }).join('');
    var sections = '';
    if (useCases) sections += '<section><h2>이럴 때 사용해요</h2><ul>' + useCases + '</ul></section>';
    if (content.howItWorks) sections += '<section><h2>어떻게 계산하나요?</h2><p>' + esc(content.howItWorks) + '</p></section>';
    if (content.example) sections += '<section><h2>사용 예시</h2><p>' + esc(content.example) + '</p></section>';
    if (notes) sections += '<section><h2>알아두세요</h2><ul>' + notes + '</ul></section>';
    if (faq) sections += '<section><h2>자주 묻는 질문</h2>' + faq + '</section>';
    return sections ? '<article class="hm-seo-guide">' + sections + '</article>' : '';
  }

  async function render(root) {
    if (root.dataset.hmCalcDetailMounted === "true") return;
    root.dataset.hmCalcDetailMounted = "true";
    ensureCss();

    if (!w.HM_CALC_INDEX) {
      try { await loadScript(dist + '/data/hm-calc-registry.v1.js?v=1.4.0'); }
      catch (_) { root.innerHTML = '<div class="hm-invalid">계산기 데이터를 불러오지 못했습니다.</div>'; return; }
    }

    var data = w.HM_CALC_INDEX || {categories:[], calculators:[]};
    var categories = (data.categories || []).filter(function (c) { return c.enabled !== false; }).sort(function (a,b) { return (a.order || 0) - (b.order || 0); });
    var calculators = (data.calculators || []).filter(function (c) { return c.enabled !== false && c.published === true; });
    var id = root.getAttribute('data-calculator-id') || '';
    var categoryId = root.getAttribute('data-category-id') || '';
    if (!id) {
      try {
        var params = new URLSearchParams(w.location.search);
        id = params.get('id') || '';
        categoryId = categoryId || params.get('category') || '';
      } catch (_) {}
    }
    var calc = calculators.find(function (c) { return c.id === id; });
    if (!calc) {
      root.innerHTML = '<div class="hm-invalid"><h1>현재 공개된 계산기가 아닙니다.</h1><p>이용 가능한 계산기를 선택해 주세요.</p><a href="' + esc(base + '/') + '">계산기 카테고리로 돌아가기</a></div>';
      return;
    }

    var selectedCat = categories.find(function (c) { return c.id === categoryId && belongs(calc, c.id) && isCategoryAvailable(c, calculators); });
    if (!selectedCat) selectedCat = categories.find(function (c) { return c.id === (calc.primaryCategory || calc.category || 'life'); });
    if (!selectedCat) selectedCat = categories[0] || {id:'life', name:'생활'};
    var related = categoryCalcs(calculators, selectedCat.id).filter(function (c) { return c.id !== calc.id; }).slice(0, 4);
    var embedded = root.getAttribute('data-embedded') === 'true';

    if (!embedded) {
      d.title = calc.name + ' | 힐링편의점';
      var meta = d.querySelector('meta[name="description"]');
      if (meta) meta.content = calc.description || (calc.name + '를 간편하게 이용하세요.');
    }

    root.classList.add('hm-calc-detail-shell', 'is-' + selectedCat.id);
    root.innerHTML =
      (embedded ? '' : '<header class="hm-detail-brandbar"><a class="hm-detail-brand" href="' + esc(base + '/') + '"><span class="hm-detail-brand-mark">H</span><span>힐링편의점 계산기<small>HEALING MART</small></span></a><a class="hm-detail-home" href="https://www.healing-mart.com/p/qna.html">오류·문의</a></header>') +
      navHtml(categories, calculators, selectedCat.id) +
      '<div class="hm-detail-main">' +
        '<header class="hm-detail-heading">' +
          '<div class="hm-detail-breadcrumb"><a href="' + esc(base + '/') + '">계산기</a><span>›</span><a href="' + esc(categoryHref(selectedCat.id)) + '">' + esc(selectedCat.name) + '</a></div>' +
          '<span class="hm-detail-category-badge is-' + esc(selectedCat.id) + '">' + icon(selectedCat.id) + esc(selectedCat.name) + '</span>' +
          '<h1 class="hm-detail-title">' + esc(calc.name) + '</h1>' +
          '<p class="hm-detail-desc">' + esc(calc.description || '') + '</p>' +
        '</header>' +
        '<div id="hm-calc-page-root-' + esc(calc.id) + '" data-hm-calculator="' + esc(calc.id) + '"></div>' +
        contentHtml(calc) +
        (related.length ? '<section class="hm-detail-related"><div class="hm-detail-related-head"><h2>같은 카테고리 계산기</h2><a href="' + esc(categoryHref(selectedCat.id)) + '">' + esc(selectedCat.name) + ' 전체보기 →</a></div><div class="hm-related-grid">' + related.map(function (c) { return '<a class="hm-related-card" href="' + esc(calculatorHref(c, selectedCat.id)) + '">' + esc(c.name) + '<span>→</span></a>'; }).join('') + '</div></section>' : '') +
        '<aside class="hm-directory-notice hm-detail-notice"><span class="hm-directory-notice-dot" aria-hidden="true"></span><div><strong>계산기는 계속 추가되고 있습니다.</strong><p>계산 결과 오류나 필요한 계산기 제안은 오류·문의 페이지에 남겨주세요.</p></div><a href="https://www.healing-mart.com/p/qna.html">오류·문의 바로가기 →</a></aside>' +
      '</div>';

    cleanTextNodes(root);

    try {
      if (!w.HM_CALC || !w.HM_CALC.mount) {
        await loadScript(dist + '/js/hm-calc-loader.v1.min.js?v=1.4.0', {'data-base': base});
      } else {
        var loader = d.createElement('script');
        loader.src = dist + '/js/hm-calc-loader.v1.min.js?v=1.4.0';
        loader.setAttribute('data-base', base);
        d.body.appendChild(loader);
      }
    } catch (err) {
      var widget = root.querySelector('[data-hm-calculator]');
      if (widget) widget.innerHTML = '<div class="hm-calc-error">계산기를 불러오지 못했습니다. 잠시 후 다시 시도해 주세요.</div>';
      console.error(err);
    }
  }

  async function boot() {
    var roots = Array.prototype.slice.call(d.querySelectorAll('[data-hm-calc-detail]'));
    for (var i = 0; i < roots.length; i += 1) await render(roots[i]);
  }

  if (d.readyState === 'loading') d.addEventListener('DOMContentLoaded', boot, {once:true});
  else boot();
})(window, document);
